const MONTH_ORDER = ["JANUARY","FEBRUARY","MARCH","APRIL","MAY","JUNE","JULY","AUGUST","SEPTEMBER","OCTOBER","NOVEMBER","DECEMBER"];
const ED_UNITS = ["CCA","CCB","CCC","CCD","Triage/Pulmo"];
const ADMITTING_UNITS = ["100D","200A","200B","200D","200G","200H","200L","300A","300B","300D","300G","300H","300L","300M","400A","400B","400D","400G","400H","400L","500A","500B","500D","500G","500M","CCL","CCU","CICU","DENTAL OR","GH-TRAUMA","HMU","ICU-TRAUMA","MATERNITY ICU","ONCO","PACU","PICU","T1A1","T1A2","T1A4","T1A5","T1A6","T1B1","T1B2","T1B4","T1B5","T1B6","T2B6"];
const SHIFTS = ["MORNING","EVENING","NIGHT"];
const TARGET = 80;
const LOGO = "data:image/jpeg;base64,";

// ── Light theme matching reference dashboard ──────────────────────────────
const C = {
  bg:"#f0f4f8",
  sidebar:"#1a2535",
  sidebarActive:"#2d3f55",
  card:"#ffffff",
  card2:"#f8fafc",
  border:"#e2e8f0",
  text:"#1a2535",
  muted:"#64748b",
  // KPI accent colors (top border per card, matching screenshot)
  blue:"#3b82f6",
  red:"#ef4444",
  amber:"#f59e0b",
  green:"#22c55e",
  purple:"#8b5cf6",
  navy:"#1e3a5f",
  // Chart colors
  chartGreen:"#22c55e",
  chartRed:"#ef4444",
  chartBlue:"#3b82f6",
  chartAmber:"#f59e0b",
  chartPurple:"#8b5cf6",
  chartTeal:"#14b8a6",
  // Status
  success:"#16a34a",
  danger:"#dc2626",
  warning:"#d97706",
  primary:"#2563eb",
  orange:"#ea580c",
  gradient:"linear-gradient(135deg,#1e3a5f 0%,#2563eb 100%)",
};
const UNIT_COLORS = [C.chartBlue,C.chartGreen,C.chartAmber,C.chartRed,C.chartPurple,C.chartTeal];

function avg(arr){return arr.length?arr.reduce((a,b)=>a+b,0)/arr.length:0;}
function med(arr){if(!arr.length)return 0;const s=[...arr].sort((a,b)=>a-b);const m=Math.floor(s.length/2);return s.length%2?s[m]:(s[m-1]+s[m])/2;}
function pct(a,b){return b?+(a/b*100).toFixed(1):0;}
function monthFromDate(d){if(!d)return"JANUARY";try{const m=new Date(d+"T12:00:00").getMonth();return MONTH_ORDER[m]||"JANUARY";}catch{return"JANUARY";}}

// KPI Card — white card with colored top border, matching screenshot style
function KPICard({title,value,sub,subColor,accent}){
  return(
    <div style={{background:C.card,borderRadius:8,padding:"20px 22px",
      borderTop:`4px solid ${accent}`,boxShadow:"0 1px 6px #0000000f",
      display:"flex",flexDirection:"column",gap:6}}>
      <div style={{fontSize:11,fontWeight:700,color:C.muted,letterSpacing:"0.07em",textTransform:"uppercase"}}>{title}</div>
      <div style={{fontSize:36,fontWeight:800,color:C.text,lineHeight:1,fontVariantNumeric:"tabular-nums"}}>{value}</div>
      {sub&&<div style={{fontSize:12,color:subColor||C.muted,fontWeight:600,marginTop:2}}>{sub}</div>}
    </div>
  );
}

function Badge({label,color,bg}){
  return <span style={{background:bg||color+"18",color,borderRadius:5,padding:"2px 9px",fontSize:11,fontWeight:700}}>{label}</span>;
}

function SidebarItem({icon,label,active,onClick}){
  return(
    <div onClick={onClick} style={{display:"flex",alignItems:"center",gap:10,padding:"10px 16px",cursor:"pointer",
      background:active?C.sidebarActive:"transparent",borderLeft:active?"3px solid #3b82f6":"3px solid transparent",
      color:active?"#e2e8f0":"#8da4be",fontSize:13,fontWeight:active?700:500,transition:"all 0.15s",borderRadius:"0 6px 6px 0",margin:"1px 0"}}>
      <span style={{fontSize:16}}>{icon}</span>{label}
    </div>
  );
}

export default function EDDispositionTracker(){
  const [allData, setAllData] = useState(() => {
  const savedData = localStorage.getItem("edTrackerData");
  if (savedData) {
    return JSON.parse(savedData);
  }
  return HISTORICAL_DATA.map((r, i) => ({ ...r, id: r.id || `h${i}` }));
  });

useEffect(() => {
  localStorage.setItem("edTrackerData", JSON.stringify(allData));
}, [allData]);
  const [view,setView]=useState("overview");
  const [filterMonth,setFilterMonth]=useState("ALL");
  const [filterUnit,setFilterUnit]=useState("ALL");
  const [filterShift,setFilterShift]=useState("ALL");
  const [showExcluded,setShowExcluded]=useState("ALL");
  const [loading, setLoading] = useState(false);
  const [saveStatus,setSaveStatus]=useState("");
  const [searchPid,setSearchPid]=useState("");
  const [editRow,setEditRow]=useState(null);
  const [datePage,setDataPage]=useState(0);
  const [sortCol,setSortCol]=useState("date");
  const [sortDir,setSortDir]=useState("desc");
  const PAGE_SIZE=25;

  const today=new Date().toISOString().slice(0,10);
  const blankForm={shift:"MORNING",pid:"",unit:"CCA",admit:"T1A5",date:today,
    alloc_wa:"",alloc_wt:"",arrival:"",disp_hm:"",disp_min:"",
    under30:"YES",delay:"0",delay_cat:"NO DELAY",month:monthFromDate(today),
    comments:"",excluded:"NO"};
  const [form,setForm]=useState(blankForm);

useEffect(() => {
  const savedData = localStorage.getItem("edTrackerData");
  if (savedData) {
    setAllData(JSON.parse(savedData));
  } else {
    setAllData(HISTORICAL_DATA.map((r, i) => ({ ...r, id: r.id || `h${i}` })));
  }
  setLoading(false);
}, []);

useEffect(() => {
  localStorage.setItem("edTrackerData", JSON.stringify(allData));
}, [allData]);
  
  const activeData=useMemo(()=>allData.filter(r=>r.excluded!=="YES"),[allData]);

  const dashData=useMemo(()=>activeData.filter(r=>{
    if(filterMonth!=="ALL"&&r.month!==filterMonth)return false;
    if(filterUnit!=="ALL"&&r.unit!==filterUnit)return false;
    if(filterShift!=="ALL"&&r.shift!==filterShift)return false;
    return true;
  }),[activeData,filterMonth,filterUnit,filterShift]);

  const filtered=useMemo(()=>{
    let d=allData.filter(r=>{
      if(filterMonth!=="ALL"&&r.month!==filterMonth)return false;
      if(filterUnit!=="ALL"&&r.unit!==filterUnit)return false;
      if(filterShift!=="ALL"&&r.shift!==filterShift)return false;
      if(showExcluded==="YES"&&r.excluded!=="YES")return false;
      if(showExcluded==="NO"&&r.excluded==="YES")return false;
      if(searchPid&&!String(r.pid).toLowerCase().includes(searchPid.toLowerCase()))return false;
      return true;
    });
    return [...d].sort((a,b)=>{
      let av=a[sortCol]??"",bv=b[sortCol]??"";
      if(sortCol==="disp_min"){av=Number(av)||0;bv=Number(bv)||0;}
      if(av<bv)return sortDir==="asc"?-1:1;
      if(av>bv)return sortDir==="asc"?1:-1;
      return 0;
    });
  },[allData,filterMonth,filterUnit,filterShift,showExcluded,searchPid,sortCol,sortDir]);

  const kpis=useMemo(()=>{
    const total=dashData.length;
    const excTotal=allData.filter(r=>r.excluded==="YES").length;
    const u30=dashData.filter(r=>r.under30==="YES").length;
    const rate=pct(u30,total);
    const mins=dashData.filter(r=>r.disp_min>0).map(r=>Number(r.disp_min));
    const avgM=mins.length?Math.round(avg(mins)):0;
    const medM=mins.length?Math.round(med(mins)):0;
    const o30act=dashData.filter(r=>Number(r.disp_min)>30&&r.disp_min>0).length;
    const o60=dashData.filter(r=>Number(r.disp_min)>60).length;
    const cancelled=excTotal;
    return{total,excTotal,u30,rate,avgM,medM,o30:o30act,o60,cancelled};
  },[dashData,allData]);

  const byUnit=useMemo(()=>{
    const map={};
    dashData.forEach(r=>{
      if(!ED_UNITS.includes(r.unit))return;
      if(!map[r.unit])map[r.unit]={unit:r.unit,total:0,u30:0,delayed:0,mins:[]};
      map[r.unit].total++;
      if(r.under30==="YES")map[r.unit].u30++;
      else map[r.unit].delayed++;
      if(r.disp_min>0)map[r.unit].mins.push(Number(r.disp_min));
    });
    return ED_UNITS.filter(u=>map[u]).map((u,i)=>({
      ...map[u],pct:pct(map[u].u30,map[u].total),
      avg:Math.round(avg(map[u].mins)),color:UNIT_COLORS[i]
    })).sort((a,b)=>b.total-a.total);
  },[dashData]);

  const byShift=useMemo(()=>{
    const map={};
    dashData.forEach(r=>{
      if(!SHIFTS.includes(r.shift))return;
      if(!map[r.shift])map[r.shift]={shift:r.shift,total:0,u30:0};
      map[r.shift].total++;
      if(r.under30==="YES")map[r.shift].u30++;
    });
    return SHIFTS.map(s=>({shift:s,total:map[s]?.total||0,u30:map[s]?.u30||0,pct:map[s]?pct(map[s].u30,map[s].total):0}));
  },[dashData]);

  const monthlyTrend=useMemo(()=>{
    const src=activeData.filter(r=>{
      if(filterUnit!=="ALL"&&r.unit!==filterUnit)return false;
      if(filterShift!=="ALL"&&r.shift!==filterShift)return false;
      return true;
    });
    const map={};
    src.forEach(r=>{
      if(!MONTH_ORDER.includes(r.month))return;
      if(!map[r.month])map[r.month]={month:r.month.slice(0,3),total:0,u30:0,mins:[]};
      map[r.month].total++;
      if(r.under30==="YES")map[r.month].u30++;
      if(r.disp_min>0)map[r.month].mins.push(Number(r.disp_min));
    });
    return MONTH_ORDER.filter(m=>map[m]).map(m=>({
      ...map[m],rate:pct(map[m].u30,map[m].total),avg:Math.round(avg(map[m].mins)),med:Math.round(med(map[m].mins))
    }));
  },[activeData,filterUnit,filterShift]);

  const dailyTrend=useMemo(()=>{
    const map={};
    dashData.forEach(r=>{
      if(!r.date)return;
      if(!map[r.date])map[r.date]={date:r.date,total:0,u30:0};
      map[r.date].total++;
      if(r.under30==="YES")map[r.date].u30++;
    });
    return Object.values(map).sort((a,b)=>a.date.localeCompare(b.date)).map(d=>({...d,rate:pct(d.u30,d.total),label:d.date.slice(5)}));
  },[dashData]);

  const excludedByReason=useMemo(()=>{
    const map={};
    allData.filter(r=>r.excluded==="YES").forEach(r=>{
      const reason=(r.comments||"").trim().toUpperCase();
      const norm=reason.includes("CANCEL")?"IP Admission Cancelled":reason.includes("OR")?"Sent to OR":reason.includes("CCL")?"Sent to CCL":reason.includes("IR")?"Sent to IR":reason.includes("DIALYSIS")?"On Dialysis":"Other";
      map[norm]=(map[norm]||0)+1;
    });
    return Object.entries(map).sort((a,b)=>b[1]-a[1]).map(([name,value],i)=>({name,value,color:UNIT_COLORS[i%6]}));
  },[allData]);

  // Export CSV
  function exportCSV(){
    const rows=[["SHIFT","PATIENT ID","ED UNIT","ADMITTING UNIT","DATE","ALLOC WA","ALLOC WATHEEQ","ARRIVAL","DISP H:MM","DISP MIN","<=30 MIN","DELAY","DELAY CAT","MONTH","COMMENTS","EXCLUDED"]];
    allData.forEach(r=>rows.push([r.shift,r.pid,r.unit,r.admit,r.date,r.alloc_wa,r.alloc_wt,r.arrival,r.disp_hm,r.disp_min,r.under30,r.delay,r.delay_cat,r.month,r.comments,r.excluded]));
    const csv=rows.map(r=>r.map(v=>`"${String(v||"").replace(/"/g,'""')}"`).join(",")).join("\n");
    const blob=new Blob([csv],{type:"text/csv"});
    const a=document.createElement("a");
    a.href=URL.createObjectURL(blob);
    a.download=`ED_Disposition_${new Date().toISOString().slice(0,10)}.csv`;
    a.click();
  }

  function handleFormChange(k,v){
    setForm(f=>{
      const nf={...f,[k]:v};
      if(k==="date")nf.month=monthFromDate(v);
      if(k==="disp_min"&&v!==""){const m=parseInt(v)||0;nf.under30=m<=30?"YES":"NO";nf.delay_cat=m<=30?"NO DELAY":"DELAY >30 min";}
      return nf;
    });
  }

  function handleSubmit(){
    if(!form.pid||!form.date||form.disp_min===""){alert("Please fill in Patient ID, Date, and Disposition Time.");return;}
    const entry={...form,disp_min:Number(form.disp_min)||0,delay:Number(form.delay)||0,id:editRow?editRow.id:`u${Date.now()}`};
    const newData=editRow?allData.map(r=>r.id===editRow.id?entry:r):[...allData,entry];
    setAllData(newData);
    setForm({...blankForm,date:today,month:monthFromDate(today)});
    setEditRow(null);setView("log");setDataPage(0);
  }

  function handleEdit(r){setEditRow(r);setForm({...r,disp_min:String(r.disp_min||""),delay:String(r.delay||"0")});setView("add");window.scrollTo(0,0);}
  function handleDelete(id){
  if (!window.confirm("Delete this record?")) return;
  const nd = allData.filter(r => r.id !== id);
  setAllData(nd);
}
  function toggleSort(col){if(sortCol===col)setSortDir(d=>d==="asc"?"desc":"asc");else{setSortCol(col);setSortDir("asc");}setDataPage(0);}

  const pageCount=Math.ceil(filtered.length/PAGE_SIZE);
  const pageData=filtered.slice(datePage*PAGE_SIZE,(datePage+1)*PAGE_SIZE);

  const selStyle={background:"white",color:C.text,border:`1px solid ${C.border}`,borderRadius:6,padding:"7px 11px",fontSize:13,cursor:"pointer",outline:"none"};
  const inpStyle={background:"white",color:C.text,border:`1px solid ${C.border}`,borderRadius:6,padding:"8px 12px",fontSize:13,outline:"none",width:"100%",boxSizing:"border-box"};
  const labelStyle={fontSize:11,color:C.muted,fontWeight:600,letterSpacing:"0.05em",textTransform:"uppercase",marginBottom:5,display:"block"};

  if(loading){
    return(
      <div style={{background:C.bg,minHeight:"100vh",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'Segoe UI',system-ui,sans-serif"}}>
        <div style={{textAlign:"center"}}>
          <img src={LOGO} alt="KSMC" style={{height:80,objectFit:"contain",marginBottom:20}}/>
          <div style={{fontSize:18,fontWeight:800,color:C.text,marginBottom:8}}>ED DISPOSITION TRACKER</div>
          <div style={{color:C.muted,fontSize:13}}>Loading {HISTORICAL_DATA.length.toLocaleString()} records...</div>
        </div>
      </div>
    );
  }

  return(
    <div style={{display:"flex",minHeight:"100vh",fontFamily:"'Segoe UI',system-ui,sans-serif",background:C.bg}}>

      {/* ── SIDEBAR ── */}
      <div style={{width:220,background:C.sidebar,display:"flex",flexDirection:"column",flexShrink:0,position:"sticky",top:0,height:"100vh",overflowY:"auto"}}>
        {/* Logo area */}
        <div style={{padding:"16px 12px 12px",borderBottom:"1px solid #2d3f55"}}>
          <img src={LOGO} alt="KSMC" style={{width:"100%",maxHeight:56,objectFit:"contain",filter:"brightness(1.15)"}}/>
        </div>
        {/* Nav title */}
        <div style={{padding:"16px 16px 6px",fontSize:10,color:"#4a6080",fontWeight:700,letterSpacing:"0.1em"}}>NAVIGATION</div>
        <SidebarItem icon="📊" label="Overview" active={view==="overview"} onClick={()=>setView("overview")}/>
        <SidebarItem icon="🏢" label="Unit Performance" active={view==="units"} onClick={()=>setView("units")}/>
        <SidebarItem icon="🔄" label="Shift Analysis" active={view==="shifts"} onClick={()=>setView("shifts")}/>
        <SidebarItem icon="📋" label="Disposition Log" active={view==="log"} onClick={()=>setView("log")}/>
        <div style={{padding:"16px 16px 6px",marginTop:8,fontSize:10,color:"#4a6080",fontWeight:700,letterSpacing:"0.1em"}}>ACTIONS</div>
        <SidebarItem icon="➕" label="Add Record" active={view==="add"} onClick={()=>{setEditRow(null);setView("add");}}/>
        <SidebarItem icon="📥" label="Export CSV" active={false} onClick={exportCSV}/>
        <div style={{flex:1}}/>
        <div style={{padding:"12px 16px",borderTop:"1px solid #2d3f55",fontSize:10,color:"#4a6080"}}>
          <div style={{fontWeight:700,marginBottom:2,color:"#6b8fa3"}}>ED DISPOSITION TRACKER</div>
          <div>Total: {allData.length.toLocaleString()} records</div>
          {saveStatus==="saved"&&<div style={{color:"#22c55e",marginTop:4}}>✓ Saved</div>}
          {saveStatus==="saving"&&<div style={{color:"#f59e0b",marginTop:4}}>Saving...</div>}
        </div>
      </div>

      {/* ── MAIN CONTENT ── */}
      <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"auto"}}>
        {/* Top bar */}
        <div style={{background:"white",borderBottom:`1px solid ${C.border}`,padding:"0 24px",display:"flex",alignItems:"center",justifyContent:"space-between",height:56,flexShrink:0,boxShadow:"0 1px 4px #0000000a"}}>
          <div>
            <div style={{fontWeight:800,fontSize:18,color:C.text}}>
              {view==="overview"?"ED Disposition Monitor":view==="units"?"Unit Performance":view==="shifts"?"Shift Analysis":view==="log"?"Disposition Log":view==="add"?(editRow?"Edit Record":"Add New Record"):""}
            </div>
            <div style={{fontSize:12,color:C.muted}}>
              {filterMonth!=="ALL"?filterMonth.slice(0,3):"All months"} · {dashData.length.toLocaleString()} dispositions · King Saud Medical City
            </div>
          </div>
          <div style={{display:"flex",gap:8,alignItems:"center"}}>
            <div style={{display:"flex",alignItems:"center",gap:5,fontSize:12,color:C.success,fontWeight:700}}>
              <div style={{width:7,height:7,borderRadius:"50%",background:C.success,animation:"pulse 2s infinite"}}/>Live
            </div>
            <button onClick={()=>{setEditRow(null);setView("add");}} style={{
              background:C.gradient,color:"white",border:"none",borderRadius:7,
              padding:"8px 16px",cursor:"pointer",fontWeight:700,fontSize:13}}>+ Add Record</button>
          </div>
        </div>

        <div style={{flex:1,padding:"20px 24px",overflowY:"auto"}}>

          {/* ── Filter Bar (shared across views) ── */}
          {(view==="overview"||view==="units"||view==="shifts")&&(
            <div style={{display:"flex",gap:10,marginBottom:20,flexWrap:"wrap",alignItems:"center"}}>
              <div style={{display:"flex",alignItems:"center",gap:6}}>
                <span style={{fontSize:12,color:C.muted,fontWeight:600}}>Shift</span>
                <select value={filterShift} onChange={e=>setFilterShift(e.target.value)} style={selStyle}>
                  <option value="ALL">All shifts</option>
                  {SHIFTS.map(s=><option key={s}>{s}</option>)}
                </select>
              </div>
              <div style={{display:"flex",alignItems:"center",gap:6}}>
                <span style={{fontSize:12,color:C.muted,fontWeight:600}}>ED Unit</span>
                <select value={filterUnit} onChange={e=>setFilterUnit(e.target.value)} style={selStyle}>
                  <option value="ALL">All units</option>
                  {ED_UNITS.map(u=><option key={u}>{u}</option>)}
                </select>
              </div>
              <div style={{display:"flex",alignItems:"center",gap:6}}>
                <span style={{fontSize:12,color:C.muted,fontWeight:600}}>Month</span>
                <select value={filterMonth} onChange={e=>setFilterMonth(e.target.value)} style={selStyle}>
                  <option value="ALL">All months</option>
                  {MONTH_ORDER.map(m=><option key={m} value={m}>{m.slice(0,3)}</option>)}
                </select>
              </div>
              {(filterMonth!=="ALL"||filterUnit!=="ALL"||filterShift!=="ALL")&&(
                <button onClick={()=>{setFilterMonth("ALL");setFilterUnit("ALL");setFilterShift("ALL");}}
                  style={{background:"transparent",color:C.danger,border:`1px solid ${C.danger}44`,borderRadius:6,padding:"6px 12px",cursor:"pointer",fontSize:12,fontWeight:600}}>✕ Clear</button>
              )}
              <span style={{marginLeft:"auto",fontSize:12,color:C.muted}}><b style={{color:C.text}}>{dashData.length.toLocaleString()}</b> active records</span>
            </div>
          )}

          {/* ══════════ OVERVIEW ══════════ */}
          {view==="overview"&&(
            <div style={{display:"flex",flexDirection:"column",gap:20}}>

              {/* KPI Cards - matching screenshot style */}
              <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(180px,1fr))",gap:14}}>
                <KPICard title="Total Admissions" value={kpis.total.toLocaleString()} sub={`${kpis.excTotal} excluded`} subColor={C.muted} accent={C.blue}/>
                <KPICard title="Within 30 Min" value={kpis.u30.toLocaleString()} sub={`${kpis.rate}% compliance`} subColor={kpis.rate>=TARGET?C.success:C.danger} accent={C.green}/>
                <KPICard title="Delayed (>30 Min)" value={kpis.o30.toLocaleString()} sub={`${pct(kpis.o30,kpis.total)}% of total`} subColor={C.danger} accent={C.red}/>
                <KPICard title="Avg Transfer Time" value={`${kpis.avgM}m`} sub={`Median ${kpis.medM}m`} subColor={C.warning} accent={C.amber}/>
                <KPICard title=">60 Min Cases" value={kpis.o60.toLocaleString()} sub={`${pct(kpis.o60,kpis.total)}%`} subColor={kpis.o60>0?C.danger:C.success} accent={C.red}/>
                <KPICard title="Excluded Cases" value={kpis.excTotal.toLocaleString()} sub={`${pct(kpis.excTotal,kpis.total+kpis.excTotal)}% of all records`} subColor={C.muted} accent={C.navy}/>
              </div>

              {/* Row 2: Compliance vs Delayed + Avg Disposition Time */}
              <div style={{display:"grid",gridTemplateColumns:"1.2fr 1fr",gap:16}}>
                <div style={{background:C.card,borderRadius:8,padding:"20px",boxShadow:"0 1px 6px #0000000f",border:`1px solid ${C.border}`}}>
                  <div style={{fontWeight:700,fontSize:15,color:C.text,marginBottom:4}}>Compliance vs Delayed by ED Unit</div>
                  <div style={{fontSize:12,color:C.muted,marginBottom:16}}>Green = ≤30 min &nbsp;·&nbsp; Red = &gt;30 min</div>
                  <ResponsiveContainer width="100%" height={260}>
                    <BarChart data={byUnit} margin={{left:0,right:10}}>
                      <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0"/>
                      <XAxis dataKey="unit" tick={{fill:C.muted,fontSize:12}} stroke={C.border}/>
                      <YAxis tick={{fill:C.muted,fontSize:11}} stroke={C.border}/>
                      <Tooltip contentStyle={{background:"white",border:`1px solid ${C.border}`,borderRadius:8,color:C.text,boxShadow:"0 4px 16px #0002"}}/>
                      <Legend wrapperStyle={{fontSize:12,color:C.muted,paddingTop:8}}/>
                      <Bar dataKey="u30" name="Within 30 min" fill={C.chartGreen} stackId="a" radius={[0,0,0,0]}/>
                      <Bar dataKey="delayed" name="Delayed" fill={C.chartRed} stackId="a" radius={[4,4,0,0]}/>
                    </BarChart>
                  </ResponsiveContainer>
                </div>

                <div style={{background:C.card,borderRadius:8,padding:"20px",boxShadow:"0 1px 6px #0000000f",border:`1px solid ${C.border}`}}>
                  <div style={{fontWeight:700,fontSize:15,color:C.text,marginBottom:4}}>Avg Disposition Time per Unit (min)</div>
                  <div style={{fontSize:12,color:C.muted,marginBottom:16}}>30-min target line shown</div>
                  <ResponsiveContainer width="100%" height={260}>
                    <BarChart data={byUnit} margin={{left:0,right:10}}>
                      <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0"/>
                      <XAxis dataKey="unit" tick={{fill:C.muted,fontSize:12}} stroke={C.border}/>
                      <YAxis tick={{fill:C.muted,fontSize:11}} stroke={C.border}/>
                      <Tooltip contentStyle={{background:"white",border:`1px solid ${C.border}`,borderRadius:8,color:C.text}} formatter={v=>[`${v} min`,"Avg Time"]}/>
                      <Bar dataKey="avg" name="Avg Time (min)" radius={[4,4,0,0]}>
                        {byUnit.map((e,i)=><Cell key={i} fill={UNIT_COLORS[i%6]}/>)}
                      </Bar>
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              </div>

              {/* Row 3: Monthly Trend + Daily Volume */}
              <div style={{display:"grid",gridTemplateColumns:"1.3fr 1fr",gap:16}}>
                <div style={{background:C.card,borderRadius:8,padding:"20px",boxShadow:"0 1px 6px #0000000f",border:`1px solid ${C.border}`}}>
                  <div style={{fontWeight:700,fontSize:15,color:C.text,marginBottom:4}}>Monthly Compliance Trend</div>
                  <div style={{fontSize:12,color:C.muted,marginBottom:16}}>≤30 min rate — target {TARGET}%</div>
                  <ResponsiveContainer width="100%" height={220}>
                    <LineChart data={monthlyTrend}>
                      <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0"/>
                      <XAxis dataKey="month" tick={{fill:C.muted,fontSize:12}} stroke={C.border}/>
                      <YAxis tick={{fill:C.muted,fontSize:11}} stroke={C.border} domain={[0,100]} unit="%"/>
                      <Tooltip contentStyle={{background:"white",border:`1px solid ${C.border}`,borderRadius:8,color:C.text}} formatter={(v,n)=>n.includes("Rate")?`${v}%`:`${v} min`}/>
                      <Legend wrapperStyle={{fontSize:12}}/>
                      <Line type="monotone" dataKey="rate" name="≤30 Min Rate %" stroke={C.chartBlue} strokeWidth={3} dot={{r:5,fill:C.chartBlue,strokeWidth:0}}/>
                      <Line type="monotone" dataKey="avg" name="Avg Time (min)" stroke={C.chartAmber} strokeWidth={2} strokeDasharray="5 3" dot={{r:3,fill:C.chartAmber,strokeWidth:0}}/>
                    </LineChart>
                  </ResponsiveContainer>
                </div>

                <div style={{background:C.card,borderRadius:8,padding:"20px",boxShadow:"0 1px 6px #0000000f",border:`1px solid ${C.border}`}}>
                  <div style={{fontWeight:700,fontSize:15,color:C.text,marginBottom:4}}>Exclusion Breakdown</div>
                  <div style={{fontSize:12,color:C.muted,marginBottom:14}}>{kpis.excTotal} excluded records by reason</div>
                  <div style={{display:"flex",flexDirection:"column",gap:10}}>
                    {excludedByReason.map((r,i)=>{
                      const max=excludedByReason[0]?.value||1;
                      return(
                        <div key={r.name}>
                          <div style={{display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:4}}>
                            <div style={{display:"flex",alignItems:"center",gap:6}}>
                              <div style={{width:10,height:10,borderRadius:3,background:r.color,flexShrink:0}}/>
                              <span style={{color:C.text,fontWeight:500}}>{r.name}</span>
                            </div>
                            <span style={{color:r.color,fontWeight:700}}>{r.value}</span>
                          </div>
                          <div style={{background:"#f0f4f8",borderRadius:4,height:6}}>
                            <div style={{width:`${r.value/max*100}%`,height:"100%",background:r.color,borderRadius:4}}/>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* ══════════ UNIT PERFORMANCE ══════════ */}
          {view==="units"&&(
            <div style={{display:"flex",flexDirection:"column",gap:16}}>
              <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(200px,1fr))",gap:14}}>
                {byUnit.map((u,i)=>(
                  <div key={u.unit} style={{background:C.card,borderRadius:8,padding:"18px",boxShadow:"0 1px 6px #0000000f",border:`1px solid ${C.border}`,borderTop:`4px solid ${u.color}`}}>
                    <div style={{fontWeight:800,fontSize:16,color:C.text,marginBottom:10}}>{u.unit}</div>
                    <div style={{fontSize:30,fontWeight:900,color:u.pct>=TARGET?C.success:C.danger,marginBottom:4}}>{u.pct}%</div>
                    <div style={{fontSize:12,color:C.muted,marginBottom:12}}>≤30 min rate · {u.u30}/{u.total} cases</div>
                    <div style={{background:"#f0f4f8",borderRadius:6,height:8,overflow:"hidden",marginBottom:8}}>
                      <div style={{width:`${u.pct}%`,height:"100%",background:u.pct>=TARGET?C.success:C.danger,borderRadius:6}}/>
                    </div>
                    <div style={{display:"flex",justifyContent:"space-between",fontSize:12}}>
                      <span style={{color:C.muted}}>Avg: <b style={{color:C.text}}>{u.avg} min</b></span>
                      <span style={{color:u.pct>=TARGET?C.success:C.danger,fontWeight:700}}>{u.pct>=TARGET?"✓ On Target":"✗ Below"}</span>
                    </div>
                  </div>
                ))}
              </div>
              <div style={{background:C.card,borderRadius:8,padding:"20px",boxShadow:"0 1px 6px #0000000f",border:`1px solid ${C.border}`}}>
                <div style={{fontWeight:700,fontSize:15,color:C.text,marginBottom:16}}>Unit Performance Summary</div>
                <table style={{width:"100%",borderCollapse:"collapse",fontSize:13}}>
                  <thead><tr style={{background:"#f8fafc"}}>
                    {["ED Unit","Total Cases","Within 30 Min","Compliance Rate","Avg Time (min)","Target Gap","Status"].map(h=>(
                      <th key={h} style={{padding:"10px 14px",textAlign:"left",color:C.muted,fontWeight:700,fontSize:11,letterSpacing:"0.05em",textTransform:"uppercase",borderBottom:`2px solid ${C.border}`}}>{h}</th>
                    ))}
                  </tr></thead>
                  <tbody>
                    {byUnit.map((u,i)=>(
                      <tr key={u.unit} style={{borderBottom:`1px solid ${C.border}`}}>
                        <td style={{padding:"10px 14px",fontWeight:700,color:u.color}}>{u.unit}</td>
                        <td style={{padding:"10px 14px"}}>{u.total.toLocaleString()}</td>
                        <td style={{padding:"10px 14px"}}>{u.u30.toLocaleString()}</td>
                        <td style={{padding:"10px 14px"}}>
                          <div style={{display:"flex",alignItems:"center",gap:8}}>
                            <div style={{background:"#f0f4f8",borderRadius:4,height:6,width:80}}>
                              <div style={{width:`${u.pct}%`,height:"100%",background:u.pct>=TARGET?C.success:C.danger,borderRadius:4}}/>
                            </div>
                            <b style={{color:u.pct>=TARGET?C.success:C.danger}}>{u.pct}%</b>
                          </div>
                        </td>
                        <td style={{padding:"10px 14px",color:C.muted}}>{u.avg}</td>
                        <td style={{padding:"10px 14px",fontWeight:700,color:u.pct>=TARGET?C.success:C.danger}}>
                          {u.pct>=TARGET?`+${(u.pct-TARGET).toFixed(1)}%`:`${(u.pct-TARGET).toFixed(1)}%`}
                        </td>
                        <td style={{padding:"10px 14px"}}><Badge label={u.pct>=TARGET?"✓ On Target":"✗ Below Target"} color={u.pct>=TARGET?C.success:C.danger}/></td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* ══════════ SHIFT ANALYSIS ══════════ */}
          {view==="shifts"&&(
            <div style={{display:"flex",flexDirection:"column",gap:16}}>
              <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:14}}>
                {byShift.map((s,i)=>(
                  <div key={s.shift} style={{background:C.card,borderRadius:8,padding:"22px",boxShadow:"0 1px 6px #0000000f",border:`1px solid ${C.border}`,borderTop:`4px solid ${UNIT_COLORS[i]}`}}>
                    <div style={{fontWeight:800,fontSize:16,color:C.text,marginBottom:4}}>{s.shift}</div>
                    <div style={{fontSize:36,fontWeight:900,color:s.pct>=TARGET?C.success:C.danger,marginBottom:4}}>{s.pct}%</div>
                    <div style={{fontSize:12,color:C.muted,marginBottom:14}}>{s.u30}/{s.total} within 30 min</div>
                    <div style={{background:"#f0f4f8",borderRadius:6,height:10,overflow:"hidden"}}>
                      <div style={{width:`${s.pct}%`,height:"100%",background:s.pct>=TARGET?C.success:C.danger,borderRadius:6}}/>
                    </div>
                  </div>
                ))}
              </div>
              <div style={{background:C.card,borderRadius:8,padding:"20px",boxShadow:"0 1px 6px #0000000f",border:`1px solid ${C.border}`}}>
                <div style={{fontWeight:700,fontSize:15,marginBottom:16}}>Shift Compliance Over Time</div>
                <ResponsiveContainer width="100%" height={260}>
                  <BarChart data={byShift}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0"/>
                    <XAxis dataKey="shift" tick={{fill:C.muted,fontSize:12}} stroke={C.border}/>
                    <YAxis tick={{fill:C.muted,fontSize:11}} stroke={C.border}/>
                    <Tooltip contentStyle={{background:"white",border:`1px solid ${C.border}`,borderRadius:8}}/>
                    <Legend wrapperStyle={{fontSize:12}}/>
                    <Bar dataKey="total" name="Total Cases" fill={C.chartBlue} radius={[4,4,0,0]} maxBarSize={60}/>
                    <Bar dataKey="u30" name="Within 30 Min" fill={C.chartGreen} radius={[4,4,0,0]} maxBarSize={60}/>
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>
          )}

          {/* ══════════ DISPOSITION LOG ══════════ */}
          {view==="log"&&(
            <div>
              <div style={{display:"flex",gap:8,marginBottom:14,alignItems:"center",flexWrap:"wrap"}}>
                <div style={{display:"flex",alignItems:"center",gap:6}}>
                  <span style={{fontSize:12,color:C.muted,fontWeight:600}}>Shift</span>
                  <select value={filterShift} onChange={e=>setFilterShift(e.target.value)} style={selStyle}>
                    <option value="ALL">All shifts</option>
                    {SHIFTS.map(s=><option key={s}>{s}</option>)}
                  </select>
                </div>
                <div style={{display:"flex",alignItems:"center",gap:6}}>
                  <span style={{fontSize:12,color:C.muted,fontWeight:600}}>Unit</span>
                  <select value={filterUnit} onChange={e=>setFilterUnit(e.target.value)} style={selStyle}>
                    <option value="ALL">All units</option>
                    {ED_UNITS.map(u=><option key={u}>{u}</option>)}
                  </select>
                </div>
                <div style={{display:"flex",alignItems:"center",gap:6}}>
                  <span style={{fontSize:12,color:C.muted,fontWeight:600}}>Month</span>
                  <select value={filterMonth} onChange={e=>setFilterMonth(e.target.value)} style={selStyle}>
                    <option value="ALL">All months</option>
                    {MONTH_ORDER.map(m=><option key={m} value={m}>{m.slice(0,3)}</option>)}
                  </select>
                </div>
                {["ALL","NO","YES"].map(v=>(
                  <button key={v} onClick={()=>{setShowExcluded(v);setDataPage(0);}} style={{
                    background:showExcluded===v?C.gradient:"white",color:showExcluded===v?"white":C.muted,
                    border:`1px solid ${showExcluded===v?"transparent":C.border}`,borderRadius:6,
                    padding:"6px 12px",cursor:"pointer",fontSize:12,fontWeight:600}}>
                    {v==="ALL"?"All":v==="NO"?"Active":"Excluded"}
                  </button>
                ))}
                <input placeholder="🔍 Patient ID..." value={searchPid} onChange={e=>{setSearchPid(e.target.value);setDataPage(0);}}
                  style={{...inpStyle,width:170,minWidth:140}}/>
                <span style={{marginLeft:"auto",fontSize:12,color:C.muted}}>
                  Active: <b style={{color:C.success}}>{allData.filter(r=>r.excluded!=="YES").length.toLocaleString()}</b>
                  &nbsp;·&nbsp; Excl: <b style={{color:C.orange}}>{allData.filter(r=>r.excluded==="YES").length.toLocaleString()}</b>
                </span>
              </div>
              <div style={{background:C.card,borderRadius:8,boxShadow:"0 1px 6px #0000000f",border:`1px solid ${C.border}`,overflow:"hidden"}}>
                <div style={{overflowX:"auto"}}>
                  <table style={{width:"100%",borderCollapse:"collapse",fontSize:12.5}}>
                    <thead>
                      <tr style={{background:"#f8fafc"}}>
                        {[{k:"date",l:"Date"},{k:"shift",l:"Shift"},{k:"pid",l:"Patient ID"},{k:"unit",l:"ED Unit"},
                          {k:"admit",l:"Admitting"},{k:"alloc_wa",l:"Alloc WA"},{k:"alloc_wt",l:"Alloc Watheeq"},
                          {k:"arrival",l:"Arrival"},{k:"disp_hm",l:"Disp h:mm"},{k:"disp_min",l:"Disp min"},
                          {k:"under30",l:"≤30 Min"},{k:"delay_cat",l:"Delay Cat"},
                          {k:"excluded",l:"Status"},{k:"comments",l:"Comments"},{k:"",l:"Actions"}].map(h=>(
                          <th key={h.k} onClick={h.k?()=>toggleSort(h.k):undefined} style={{
                            padding:"10px 12px",textAlign:"left",color:sortCol===h.k?C.primary:C.muted,
                            fontWeight:700,fontSize:10,letterSpacing:"0.05em",textTransform:"uppercase",
                            borderBottom:`2px solid ${C.border}`,whiteSpace:"nowrap",cursor:h.k?"pointer":"default"}}>
                            {h.l}{sortCol===h.k?(sortDir==="asc"?" ↑":" ↓"):""}
                          </th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {pageData.map((r,i)=>(
                        <tr key={r.id||i}
                          style={{borderBottom:`1px solid ${C.border}`,background:r.excluded==="YES"?"#fff8f0":i%2===0?"white":"#fafbfc"}}
                          onMouseEnter={e=>e.currentTarget.style.background="#eff6ff"}
                          onMouseLeave={e=>e.currentTarget.style.background=r.excluded==="YES"?"#fff8f0":i%2===0?"white":"#fafbfc"}>
                          <td style={{padding:"9px 12px",color:C.muted,fontSize:11,whiteSpace:"nowrap"}}>{r.date}</td>
                          <td style={{padding:"9px 12px",whiteSpace:"nowrap"}}>
                            <Badge label={r.shift} color={r.shift==="MORNING"?"#d97706":r.shift==="EVENING"?"#2563eb":"#7c3aed"}/>
                          </td>
                          <td style={{padding:"9px 12px",fontFamily:"monospace",fontSize:11,color:C.muted}}>{r.pid}</td>
                          <td style={{padding:"9px 12px",fontWeight:700,color:C.primary,whiteSpace:"nowrap"}}>{r.unit}</td>
                          <td style={{padding:"9px 12px",whiteSpace:"nowrap",fontSize:11}}>{r.admit}</td>
                          <td style={{padding:"9px 12px",fontFamily:"monospace",fontSize:10,color:C.muted}}>{r.alloc_wa}</td>
                          <td style={{padding:"9px 12px",fontFamily:"monospace",fontSize:10,color:C.muted}}>{r.alloc_wt}</td>
                          <td style={{padding:"9px 12px",fontFamily:"monospace",fontSize:10,color:C.muted}}>{r.arrival}</td>
                          <td style={{padding:"9px 12px",fontFamily:"monospace",fontSize:11}}>{r.disp_hm}</td>
                          <td style={{padding:"9px 12px",fontWeight:800,fontSize:13,
                            color:Number(r.disp_min)<=30?"#16a34a":Number(r.disp_min)<=60?"#d97706":"#dc2626"}}>
                            {r.disp_min||"-"}
                          </td>
                          <td style={{padding:"9px 12px"}}>
                            <Badge label={r.under30||"-"} color={r.under30==="YES"?"#16a34a":r.under30==="NO"?"#dc2626":C.muted}/>
                          </td>
                          <td style={{padding:"9px 12px",fontSize:11,color:C.muted,whiteSpace:"nowrap"}}>{r.delay_cat}</td>
                          <td style={{padding:"9px 12px"}}>
                            <Badge label={r.excluded==="YES"?"EXCLUDED":"ACTIVE"} color={r.excluded==="YES"?"#ea580c":"#16a34a"}/>
                          </td>
                          <td style={{padding:"9px 12px",fontSize:10,color:C.muted,maxWidth:130,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}} title={r.comments}>{r.comments||"-"}</td>
                          <td style={{padding:"9px 12px"}}>
                            <div style={{display:"flex",gap:4}}>
                              <button onClick={()=>handleEdit(r)} style={{background:"#eff6ff",color:C.primary,border:"none",borderRadius:5,padding:"4px 8px",cursor:"pointer",fontSize:11,fontWeight:700}}>Edit</button>
                              <button onClick={()=>handleDelete(r.id)} style={{background:"#fef2f2",color:"#dc2626",border:"none",borderRadius:5,padding:"4px 8px",cursor:"pointer",fontSize:11,fontWeight:700}}>Del</button>
                            </div>
                          </td>
                        </tr>
                      ))}
                      {pageData.length===0&&(<tr><td colSpan={15} style={{padding:40,textAlign:"center",color:C.muted}}>No records match filters.</td></tr>)}
                    </tbody>
                  </table>
                </div>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"12px 16px",borderTop:`1px solid ${C.border}`,background:"#f8fafc"}}>
                  <span style={{fontSize:12,color:C.muted}}>Page <b style={{color:C.text}}>{datePage+1}</b> / <b style={{color:C.text}}>{Math.max(1,pageCount)}</b> &nbsp;·&nbsp; {filtered.length.toLocaleString()} records</span>
                  <div style={{display:"flex",gap:5}}>
                    {[{l:"«",a:()=>setDataPage(0),d:datePage===0},{l:"‹",a:()=>setDataPage(p=>p-1),d:datePage===0},
                      {l:"›",a:()=>setDataPage(p=>p+1),d:datePage>=pageCount-1},{l:"»",a:()=>setDataPage(pageCount-1),d:datePage>=pageCount-1}].map(b=>(
                      <button key={b.l} disabled={b.d} onClick={b.a} style={{background:"white",color:C.text,border:`1px solid ${C.border}`,borderRadius:5,padding:"5px 10px",cursor:b.d?"not-allowed":"pointer",opacity:b.d?0.35:1,fontSize:12}}>{b.l}</button>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* ══════════ ADD / EDIT ══════════ */}
          {view==="add"&&(
            <div style={{maxWidth:780,margin:"0 auto"}}>
              <div style={{background:C.card,borderRadius:10,padding:28,boxShadow:"0 2px 16px #0000001a",border:`1px solid ${C.border}`}}>
                <div style={{fontWeight:800,fontSize:18,color:C.text,marginBottom:4,display:"flex",alignItems:"center",gap:10}}>
                  {editRow?"✏️ Edit Record":"➕ Add New Record"}
                  {editRow&&<Badge label="Editing" color={C.warning}/>}
                </div>
                <div style={{color:C.muted,fontSize:12,marginBottom:22}}>Fields marked * are required. ≤30 Min and Month are auto-calculated.</div>
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
                  <div><label style={labelStyle}>Date of Bed Allocation *</label>
                    <input type="date" value={form.date} onChange={e=>handleFormChange("date",e.target.value)} style={inpStyle}/></div>
                  <div><label style={labelStyle}>Shift *</label>
                    <select value={form.shift} onChange={e=>handleFormChange("shift",e.target.value)} style={{...inpStyle,cursor:"pointer"}}>
                      {SHIFTS.map(s=><option key={s}>{s}</option>)}</select></div>
                  <div><label style={labelStyle}>Patient ID *</label>
                    <input type="text" value={form.pid} onChange={e=>handleFormChange("pid",e.target.value)} placeholder="e.g. 110000356396" style={inpStyle}/></div>
                  <div><label style={labelStyle}>ED Unit *</label>
                    <select value={form.unit} onChange={e=>handleFormChange("unit",e.target.value)} style={{...inpStyle,cursor:"pointer"}}>
                      {ED_UNITS.map(u=><option key={u}>{u}</option>)}</select></div>
                  <div><label style={labelStyle}>Admitting Unit *</label>
                    <select value={form.admit} onChange={e=>handleFormChange("admit",e.target.value)} style={{...inpStyle,cursor:"pointer"}}>
                      {ADMITTING_UNITS.map(u=><option key={u}>{u}</option>)}</select></div>
                  <div><label style={labelStyle}>Disposition Time (minutes) *</label>
                    <input type="number" value={form.disp_min} onChange={e=>handleFormChange("disp_min",e.target.value)} placeholder="e.g. 25" min="0" style={inpStyle}/></div>
                  <div><label style={labelStyle}>Bed Allocation Time (WhatsApp)</label>
                    <input type="time" value={form.alloc_wa.slice(0,5)||""} onChange={e=>handleFormChange("alloc_wa",e.target.value+":00")} style={inpStyle}/></div>
                  <div><label style={labelStyle}>Bed Allocation Time (Watheeq)</label>
                    <input type="time" value={form.alloc_wt.slice(0,5)||""} onChange={e=>handleFormChange("alloc_wt",e.target.value+":00")} style={inpStyle}/></div>
                  <div><label style={labelStyle}>Patient Arrival Time to Unit</label>
                    <input type="time" value={form.arrival.slice(0,5)||""} onChange={e=>handleFormChange("arrival",e.target.value+":00")} style={inpStyle}/></div>
                  <div><label style={labelStyle}>Disposition Time (h:mm:ss)</label>
                    <input type="text" value={form.disp_hm} onChange={e=>handleFormChange("disp_hm",e.target.value)} placeholder="00:25:00" style={inpStyle}/></div>
                  <div><label style={labelStyle}>WhatsApp Delay (minutes)</label>
                    <input type="number" value={form.delay} onChange={e=>handleFormChange("delay",e.target.value)} min="0" style={inpStyle}/></div>
                  <div><label style={labelStyle}>Delay Category (auto)</label>
                    <div style={{...inpStyle,background:"#f8fafc",fontWeight:700,cursor:"default",color:form.delay_cat==="DELAY >30 min"?C.danger:C.success}}>{form.delay_cat||"NO DELAY"}</div></div>
                </div>
                {/* Exclusion */}
                <div style={{marginTop:14,padding:"16px",background:"#fff8f0",borderRadius:8,border:`1px solid #fed7aa`}}>
                  <div style={{fontWeight:700,fontSize:13,marginBottom:10,color:C.orange}}>🔕 Exclusion Status</div>
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
                    <div><label style={labelStyle}>Mark as Excluded?</label>
                      <div style={{display:"flex",gap:8}}>
                        {["NO","YES"].map(v=>(
                          <button key={v} onClick={()=>handleFormChange("excluded",v)} style={{
                            flex:1,background:form.excluded===v?(v==="YES"?"#ea580c":"#16a34a"):"white",
                            color:form.excluded===v?"white":C.muted,
                            border:`1px solid ${form.excluded===v?(v==="YES"?"#ea580c":"#16a34a"):C.border}`,
                            borderRadius:6,padding:"9px",cursor:"pointer",fontWeight:700,fontSize:13}}>
                            {v==="YES"?"🔕 Excluded":"✓ Active"}
                          </button>
                        ))}
                      </div>
                    </div>
                    <div><label style={labelStyle}>Comments / Exclusion Reason</label>
                      <input type="text" value={form.comments} onChange={e=>handleFormChange("comments",e.target.value)}
                        placeholder={form.excluded==="YES"?"e.g. IP Admission cancelled...":"Optional notes"} style={inpStyle}/></div>
                  </div>
                </div>
                {/* Auto-calculated */}
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14,marginTop:14}}>
                  <div style={{background:"#f0fdf4",borderRadius:8,padding:"14px 16px",border:`1px solid #bbf7d0`}}>
                    <label style={{...labelStyle,color:"#16a34a"}}>≤30 Minutes? (auto)</label>
                    <div style={{fontSize:26,fontWeight:900,color:form.under30==="YES"?"#16a34a":"#dc2626"}}>{form.under30==="YES"?"✓ YES":"✗ NO"}</div>
                  </div>
                  <div style={{background:"#eff6ff",borderRadius:8,padding:"14px 16px",border:`1px solid #bfdbfe`}}>
                    <label style={{...labelStyle,color:C.primary}}>Month (auto from date)</label>
                    <div style={{fontSize:26,fontWeight:900,color:C.primary}}>{form.month}</div>
                  </div>
                </div>
                <div style={{display:"flex",gap:12,marginTop:20}}>
                  <button onClick={handleSubmit} style={{background:C.gradient,color:"white",border:"none",borderRadius:8,padding:"13px 32px",cursor:"pointer",fontWeight:800,fontSize:15,flex:1}}>
                    {editRow?"✓ Save Changes":"➕ Add Entry"}
                  </button>
                  <button onClick={()=>{setView("log");setEditRow(null);setForm({...blankForm,date:today,month:monthFromDate(today)});}}
                    style={{background:"white",color:C.muted,border:`1px solid ${C.border}`,borderRadius:8,padding:"13px 24px",cursor:"pointer",fontWeight:600,fontSize:14}}>
                    Cancel
                  </button>
                </div>
              </div>
            </div>
          )}

        </div>
      </div>
    </div>
  );
}
